    public class LusherTestProcessor : ITestProcessor
    {
        private readonly string _reportsDirectory;

        public LusherTestProcessor(IOptions<ReportsOptions> options)
        {
            _reportsDirectory = Path.Combine(Directory.GetCurrentDirectory(), options.Value.Directory);

            if (!Directory.Exists(_reportsDirectory))
                Directory.CreateDirectory(_reportsDirectory);
        }


        public TestResult Process(TestSession session, object answers)
        {
            var luscherAnswers = (LuscherAnswers)answers;

            List<string> positiveAnswers = SetKeys(luscherAnswers.Positive);
            List<string> negativeAnswers = SetKeys(luscherAnswers.Negative);

            var resultLines = new List<string>();
            for (int i = 0; i < Math.Max(positiveAnswers.Count, negativeAnswers.Count); i++)
            {
                if (i < positiveAnswers.Count && _results.ContainsKey(positiveAnswers[i]))
                {
                    resultLines.Add(positiveAnswers[i]);
                    resultLines.Add(_results[positiveAnswers[i]]);
                }

                if (!positiveAnswers[i].Equals(negativeAnswers[i]))
                {
                    if (i < negativeAnswers.Count && _results.ContainsKey(negativeAnswers[i]))
                    {
                        resultLines.Add(negativeAnswers[i]);
                        resultLines.Add(_results[negativeAnswers[i]]);
                    }
                }
            }

            var resultText = string.Join("\n\n", resultLines);
            //var reportPath = GenerateDocxReport(session.Id, resultText, luscherAnswers);

            var fileBytes = GenerateDocxReport(session.Id, answers, resultText);

            return new TestResult
            {
                Id = Guid.NewGuid(),
                SessionId = session.Id,
                ResultText = resultText,
                ReportBytes = fileBytes
            };
        }

        private List<string> SetKeys(List<int> answers)
        {
            var keys = new List<string>();
            keys.Add("+" + answers[0].ToString());
            for (int i = 0; i < answers.Capacity; i += 2)
            {
                if (i == 0)
                {
                    keys.Add("+" + answers[i].ToString() + "+" + answers[i + 1].ToString());
                }
                else if (i == 2)
                {
                    keys.Add("х" + answers[i].ToString() + "х" + answers[i + 1].ToString());
                }
                else if (i == 4)
                {
                    keys.Add("=" + answers[i].ToString() + "=" + answers[i + 1].ToString());
                }
                else if (i == 6)
                {
                    keys.Add("-" + answers[i].ToString() + "-" + answers[i + 1].ToString());
                }
                else
                {
                    continue;
                }
            }
            keys.Add("+" + answers[0].ToString() + "-" + answers[7].ToString());
            return keys;
        }

